+import type { Order } from '../models/order.js';
+import type { OrderStatus } from '../models/order.js';
+import type {
+  TimeSeriesDataPoint,
+  TimeGranularity,
+  OrderMetricSummary,
+  UserMetricSummary,
+  TopProduct,
+  DashboardData,
+} from '../models/analytics.js';
+import type { OrderRepository } from '../repositories/order.repository.js';
+import type { UserRepository } from '../repositories/user.repository.js';
+import { Logger } from '../utils/logger.js';
+
+const ALL_STATUSES: OrderStatus[] = [
+  'pending',
+  'confirmed',
+  'shipped',
+  'delivered',
+  'cancelled',
+];
+
+/**
+ * Truncate a date to the start of the given granularity bucket.
+ */
+function truncateDate(date: Date, granularity: TimeGranularity): string {
+  const d = new Date(date);
+  switch (granularity) {
+    case 'hour':
+      d.setMinutes(0, 0, 0);
+      return d.toISOString();
+    case 'day':
+      d.setHours(0, 0, 0, 0);
+      return d.toISOString();
+    case 'week': {
+      const day = d.getDay();
+      d.setDate(d.getDate() - day);
+      d.setHours(0, 0, 0, 0);
+      return d.toISOString();
+    }
+    case 'month':
+      d.setDate(1);
+      d.setHours(0, 0, 0, 0);
+      return d.toISOString();
+  }
+}
+
+export class AnalyticsService {
+  private logger = new Logger('AnalyticsService');
+
+  constructor(
+    private orderRepository: OrderRepository,
+    private userRepository: UserRepository,
+  ) {}
+
+  /**
+   * Aggregate orders into a time series.
+   *
+   * Groups orders by time bucket (hour, day, week, month) and returns
+   * count and revenue for each bucket, sorted chronologically.
+   */
+  aggregateTimeSeries(
+    granularity: TimeGranularity,
+    startDate?: Date,
+    endDate?: Date,
+  ): TimeSeriesDataPoint[] {
+    this.logger.info(`Aggregating time series with granularity: ${granularity}`);
+
+    let orders = this.orderRepository.findAll();
+
+    if (startDate) {
+      orders = orders.filter((o) => o.createdAt >= startDate);
+    }
+    if (endDate) {
+      orders = orders.filter((o) => o.createdAt <= endDate);
+    }
+
+    const buckets = new Map<string, { count: number; revenue: number }>();
+
+    for (const order of orders) {
+      const key = truncateDate(order.createdAt, granularity);
+      const existing = buckets.get(key);
+      if (existing) {
+        existing.count += 1;
+        existing.revenue += order.total;
+      } else {
+        buckets.set(key, { count: 1, revenue: order.total });
+      }
+    }
+
+    const result: TimeSeriesDataPoint[] = [];
+    for (const [timestamp, data] of buckets) {
+      result.push({
+        timestamp,
+        count: data.count,
+        revenue: Math.round(data.revenue * 100) / 100,
+      });
+    }
+
+    result.sort((a, b) => a.timestamp.localeCompare(b.timestamp));
+    return result;
+  }
+
+  /**
+   * Compute summary metrics for orders.
+   *
+   * Returns total orders, total revenue, average order value,
+   * and a breakdown of order counts by status.
+   */
+  getOrderMetrics(): OrderMetricSummary {
+    this.logger.info('Computing order metrics');
+
+    const orders = this.orderRepository.findAll();
+    const totalOrders = orders.length;
+    const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
+    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;
+
+    const ordersByStatus = {} as Record<OrderStatus, number>;
+    for (const status of ALL_STATUSES) {
+      ordersByStatus[status] = 0;
+    }
+    for (const order of orders) {
+      ordersByStatus[order.status] += 1;
+    }
+
+    return {
+      totalOrders,
+      totalRevenue: Math.round(totalRevenue * 100) / 100,
+      averageOrderValue: Math.round(averageOrderValue * 100) / 100,
+      ordersByStatus,
+    };
+  }
+
+  /**
+   * Compute summary metrics for users.
+   *
