+  }
+
+  /**
+   * Get order metrics filtered to a specific date range.
+   */
+  getOrderMetricsForPeriod(
+    startDate: Date,
+    endDate: Date,
+  ): OrderMetricSummary {
+    this.logger.info(
+      `Computing order metrics for period: ${startDate.toISOString()} to ${endDate.toISOString()}`,
+    );
+
+    const orders = this.orderRepository
+      .findAll()
+      .filter((o) => o.createdAt >= startDate && o.createdAt <= endDate);
+
+    return this.computeOrderMetrics(orders);
+  }
+
+  /**
+   * Compute order metrics from a given set of orders.
+   */
+  private computeOrderMetrics(orders: Order[]): OrderMetricSummary {
+    const totalOrders = orders.length;
+    const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
+    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;
