/**
 * Analytics data model definitions.
 *
 * These interfaces define the shape of aggregated analytics data
 * produced by the AnalyticsService for dashboard consumption.
 */

import type { OrderStatus } from './order.js';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesDataPoint {
  /** Start of the time bucket (ISO string) */
  timestamp: string;
  /** Number of orders in this bucket */
  count: number;
  /** Total revenue in this bucket */
  revenue: number;
}

/**
 * Time granularity for time-series aggregation.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Summary metrics for orders.
 */
export interface OrderMetricSummary {
  /** Total number of orders */
  totalOrders: number;
  /** Total revenue across all orders */
  totalRevenue: number;
  /** Average order value */
  averageOrderValue: number;
  /** Breakdown of order counts by status */
  ordersByStatus: Record<OrderStatus, number>;
}

/**
 * Summary metrics for users.
 */
export interface UserMetricSummary {
  /** Total number of users */
  totalUsers: number;
  /** Breakdown of user counts by role */
  usersByRole: Record<string, number>;
}

/**
 * Top product entry in analytics.
 */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

/**
 * Composite dashboard data combining all analytics.
 */
export interface DashboardData {
  /** Order metrics summary */
  orderMetrics: OrderMetricSummary;
  /** User metrics summary */
  userMetrics: UserMetricSummary;
  /** Time-series data for the requested period */
  timeSeries: TimeSeriesDataPoint[];
  /** Top products by revenue */
  topProducts: TopProduct[];
  /** Timestamp when this data was generated */
  generatedAt: Date;
}

/**
 * Analytics aggregation service — processes raw order and user data
 * into analytics summaries for the dashboard.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture note: This service performs read-only aggregation over
 * existing repository data. It does not maintain its own data store.
 */

import type { Order } from '../models/order.js';
import type { OrderStatus } from '../models/order.js';
import type {
  TimeSeriesDataPoint,
  TimeGranularity,
  OrderMetricSummary,
  UserMetricSummary,
  TopProduct,
  DashboardData,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

const ALL_STATUSES: OrderStatus[] = [
  'pending',
  'confirmed',
  'shipped',
  'delivered',
  'cancelled',
];

/**
 * Truncate a date to the start of the given granularity bucket.
 */
function truncateDate(date: Date, granularity: TimeGranularity): string {
  const d = new Date(date);
  switch (granularity) {
    case 'hour':
      d.setMinutes(0, 0, 0);
      return d.toISOString();
    case 'day':
      d.setHours(0, 0, 0, 0);
      return d.toISOString();
    case 'week': {
      const day = d.getDay();
      d.setDate(d.getDate() - day);
      d.setHours(0, 0, 0, 0);
      return d.toISOString();
    }
    case 'month':
      d.setDate(1);
      d.setHours(0, 0, 0, 0);
      return d.toISOString();
  }
}

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Aggregate orders into a time series.
   *
   * Groups orders by time bucket (hour, day, week, month) and returns
   * count and revenue for each bucket, sorted chronologically.
   */
  aggregateTimeSeries(
    granularity: TimeGranularity,
    startDate?: Date,
    endDate?: Date,
  ): TimeSeriesDataPoint[] {
    this.logger.info(`Aggregating time series with granularity: ${granularity}`);

    let orders = this.orderRepository.findAll();

    if (startDate) {
      orders = orders.filter((o) => o.createdAt >= startDate);
    }
    if (endDate) {
      orders = orders.filter((o) => o.createdAt <= endDate);
    }

    const buckets = new Map<string, { count: number; revenue: number }>();

    for (const order of orders) {
      const key = truncateDate(order.createdAt, granularity);
      const existing = buckets.get(key);
      if (existing) {
        existing.count += 1;
        existing.revenue += order.total;
      } else {
        buckets.set(key, { count: 1, revenue: order.total });
      }
    }

    const result: TimeSeriesDataPoint[] = [];
    for (const [timestamp, data] of buckets) {
      result.push({
        timestamp,
        count: data.count,
        revenue: Math.round(data.revenue * 100) / 100,
      });
    }

    result.sort((a, b) => a.timestamp.localeCompare(b.timestamp));
    return result;
  }

  /**
   * Compute summary metrics for orders.
   *
   * Returns total orders, total revenue, average order value,
   * and a breakdown of order counts by status.
   */
  getOrderMetrics(): OrderMetricSummary {
    this.logger.info('Computing order metrics');

    const orders = this.orderRepository.findAll();
    const totalOrders = orders.length;
    const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    const ordersByStatus = {} as Record<OrderStatus, number>;
    for (const status of ALL_STATUSES) {
      ordersByStatus[status] = 0;
    }
    for (const order of orders) {
      ordersByStatus[order.status] += 1;
    }

    return {
      totalOrders,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      averageOrderValue: Math.round(averageOrderValue * 100) / 100,
      ordersByStatus,
    };
  }

  /**
   * Compute summary metrics for users.
   *
   * Returns total users and a breakdown by role.
   */
  getUserMetrics(): UserMetricSummary {
    this.logger.info('Computing user metrics');

    const users = this.userRepository.findAll();
    const totalUsers = users.length;

    const usersByRole: Record<string, number> = {};
    for (const user of users) {
      usersByRole[user.role] = (usersByRole[user.role] ?? 0) + 1;
    }

    return { totalUsers, usersByRole };
  }

  /**
   * Get top products ranked by total revenue.
   *
   * Aggregates across all orders to find which products generate
   * the most revenue.
   */
  getTopProducts(limit: number = 10): TopProduct[] {
    this.logger.info(`Computing top ${limit} products`);

    const orders = this.orderRepository.findAll();
    const productMap = new Map<
      string,
      { name: string; totalQuantity: number; totalRevenue: number }
    >();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += item.quantity * item.unitPrice;
        } else {
          productMap.set(item.productId, {
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: item.quantity * item.unitPrice,
          });
        }
      }
    }

    const products: TopProduct[] = [];
    for (const [productId, data] of productMap) {
      products.push({
        productId,
        name: data.name,
        totalQuantity: data.totalQuantity,
        totalRevenue: Math.round(data.totalRevenue * 100) / 100,
      });
    }

    products.sort((a, b) => b.totalRevenue - a.totalRevenue);
    return products.slice(0, limit);
  }

  /**
   * Compose full dashboard data from all analytics sources.
   *
   * This is the main entry point for the analytics dashboard,
   * combining order metrics, user metrics, time series, and top products.
   */
  getDashboardData(
    granularity: TimeGranularity = 'day',
    startDate?: Date,
    endDate?: Date,
    topProductsLimit: number = 10,
  ): DashboardData {
    this.logger.info('Composing dashboard data');

    return {
      orderMetrics: this.getOrderMetrics(),
      userMetrics: this.getUserMetrics(),
      timeSeries: this.aggregateTimeSeries(granularity, startDate, endDate),
      topProducts: this.getTopProducts(topProductsLimit),
      generatedAt: new Date(),
    };
  }

  /**
   * Get order metrics filtered to a specific date range.
   */
  getOrderMetricsForPeriod(
    startDate: Date,
    endDate: Date,
  ): OrderMetricSummary {
    this.logger.info(
      `Computing order metrics for period: ${startDate.toISOString()} to ${endDate.toISOString()}`,
    );

    const orders = this.orderRepository
      .findAll()
      .filter((o) => o.createdAt >= startDate && o.createdAt <= endDate);

    return this.computeOrderMetrics(orders);
  }

  /**
   * Compute order metrics from a given set of orders.
   */
  private computeOrderMetrics(orders: Order[]): OrderMetricSummary {
    const totalOrders = orders.length;
    const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
    const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

    const ordersByStatus = {} as Record<OrderStatus, number>;
    for (const status of ALL_STATUSES) {
      ordersByStatus[status] = 0;
    }
    for (const order of orders) {
      ordersByStatus[order.status] += 1;
    }

    return {
      totalOrders,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      averageOrderValue: Math.round(averageOrderValue * 100) / 100,
      ordersByStatus,
    };
  }
}

